(()=>{let t;htmx.registerExtension("hx-prompt",{init(e){t=e},htmx_config_request(e,{ctx:r}){let m=t.attributeValue(r.sourceElement,"hx-prompt");if(null==m)return;let o=(window.htmxPrompt||window.prompt)(m);return null!==o&&(!!htmx.trigger(r.sourceElement,"htmx:prompt",{prompt:o,target:r.target})&&void(r.request.headers["HX-Prompt"]=o))}})})();